"""
Workflow data transformation module for processing step outputs.
"""
import ast
import operator


def transform_step_data(transform_map_expr: str, input_data: dict) -> dict:
    """
    Transforms input data using a provided expression string.

    Args:
        transform_map_expr: A string representing a Python dictionary literal
                           that defines how to map input fields to output fields.
        input_data: Dictionary containing the input data from a previous step.

    Returns:
        A new dictionary with transformed data according to the expression.
    """
    # Parse the expression into an AST
    try:
        tree = ast.parse(transform_map_expr, mode='eval')
    except SyntaxError as e:
        raise ValueError(f"Invalid expression syntax: {e}")

    # Evaluate the AST safely
    result = _safe_eval(tree.body, input_data)

    if not isinstance(result, dict):
        raise ValueError("Transform expression must evaluate to a dictionary")

    return result


def _safe_eval(node, input_data):
    """
    Safely evaluate an AST node with restricted operations.

    Only allows:
    - Dictionary literals
    - List literals
    - Tuple literals
    - Set literals
    - String, number, boolean, None literals
    - Subscript operations (e.g., input_data['key'])
    - Name references (only 'input_data')
    - Arithmetic operators (+, -, *, /, //, %, **)
    - Comparison operators (==, !=, <, <=, >, >=)
    - Logical operators (and, or, not)
    - Unary operators (+, -, not)
    """
    if isinstance(node, ast.Constant):
        # Python 3.8+ uses ast.Constant for all constant values
        return node.value

    elif isinstance(node, ast.Num):  # Deprecated but kept for compatibility
        return node.n

    elif isinstance(node, ast.Str):  # Deprecated but kept for compatibility
        return node.s

    elif isinstance(node, ast.NameConstant):  # Deprecated but kept for compatibility
        return node.value

    elif isinstance(node, ast.Dict):
        # Dictionary literal: {key1: value1, key2: value2}
        keys = [_safe_eval(k, input_data) for k in node.keys]
        values = [_safe_eval(v, input_data) for v in node.values]
        return dict(zip(keys, values))

    elif isinstance(node, ast.List):
        # List literal: [item1, item2]
        return [_safe_eval(item, input_data) for item in node.elts]

    elif isinstance(node, ast.Tuple):
        # Tuple literal: (item1, item2)
        return tuple(_safe_eval(item, input_data) for item in node.elts)

    elif isinstance(node, ast.Set):
        # Set literal: {item1, item2}
        return {_safe_eval(item, input_data) for item in node.elts}

    elif isinstance(node, ast.Name):
        # Variable reference - only allow 'input_data'
        if node.id == 'input_data':
            return input_data
        else:
            raise ValueError(f"Undefined variable: {node.id}. Only 'input_data' is allowed.")

    elif isinstance(node, ast.Subscript):
        # Subscript operation: obj[key]
        obj = _safe_eval(node.value, input_data)
        key = _safe_eval(node.slice, input_data)
        try:
            return obj[key]
        except (KeyError, IndexError, TypeError) as e:
            raise ValueError(f"Subscript operation failed: {e}")

    elif isinstance(node, ast.BinOp):
        # Binary operations: +, -, *, /, //, %, **
        left = _safe_eval(node.left, input_data)
        right = _safe_eval(node.right, input_data)

        ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
        }

        op_func = ops.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unsupported binary operator: {type(node.op).__name__}")

        try:
            return op_func(left, right)
        except Exception as e:
            raise ValueError(f"Binary operation failed: {e}")

    elif isinstance(node, ast.UnaryOp):
        # Unary operations: +, -, not
        operand = _safe_eval(node.operand, input_data)

        ops = {
            ast.UAdd: operator.pos,
            ast.USub: operator.neg,
            ast.Not: operator.not_,
        }

        op_func = ops.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unsupported unary operator: {type(node.op).__name__}")

        return op_func(operand)

    elif isinstance(node, ast.Compare):
        # Comparison operations: ==, !=, <, <=, >, >=
        left = _safe_eval(node.left, input_data)

        ops = {
            ast.Eq: operator.eq,
            ast.NotEq: operator.ne,
            ast.Lt: operator.lt,
            ast.LtE: operator.le,
            ast.Gt: operator.gt,
            ast.GtE: operator.ge,
        }

        # Python allows chained comparisons, so we need to handle multiple comparators
        result = True
        for op, comparator in zip(node.ops, node.comparators):
            right = _safe_eval(comparator, input_data)
            op_func = ops.get(type(op))
            if op_func is None:
                raise ValueError(f"Unsupported comparison operator: {type(op).__name__}")

            result = result and op_func(left, right)
            if not result:
                break
            left = right

        return result

    elif isinstance(node, ast.BoolOp):
        # Boolean operations: and, or
        if isinstance(node.op, ast.And):
            result = True
            for value in node.values:
                result = result and _safe_eval(value, input_data)
                if not result:
                    break
            return result
        elif isinstance(node.op, ast.Or):
            result = False
            for value in node.values:
                result = result or _safe_eval(value, input_data)
                if result:
                    break
            return result
        else:
            raise ValueError(f"Unsupported boolean operator: {type(node.op).__name__}")

    else:
        raise ValueError(f"Unsupported expression type: {type(node).__name__}")

"""
Workflow data transformation module for processing step outputs.
"""
import ast
import operator


def transform_step_data(transform_map_expr: str, input_data: dict) -> dict:
    """
    Transforms input data using a provided expression string.

    Args:
        transform_map_expr: A string representing a Python dictionary literal
                           that defines how to map input fields to output fields.
        input_data: Dictionary containing the input data from a previous step.

    Returns:
        A new dictionary with transformed data according to the expression.

    Raises:
        ValueError: If the expression contains unsafe operations.
        SyntaxError: If the expression is not valid Python syntax.
    """
    # Parse the expression into an AST
    try:
        tree = ast.parse(transform_map_expr, mode='eval')
    except SyntaxError as e:
        raise SyntaxError(f"Invalid expression syntax: {e}")

    # Validate that the expression only contains safe operations
    _validate_ast(tree)

    # Define allowed operations
    safe_operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.And: lambda a, b: a and b,
        ast.Or: lambda a, b: a or b,
        ast.Not: operator.not_,
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval_node(node):
        """Safely evaluate an AST node."""
        if isinstance(node, ast.Expression):
            return _eval_node(node.body)

        elif isinstance(node, ast.Constant):
            return node.value

        elif isinstance(node, ast.Name):
            if node.id == 'input_data':
                return input_data
            elif node.id in ('True', 'False', 'None'):
                return ast.literal_eval(node.id)
            else:
                raise ValueError(f"Undefined variable: {node.id}")

        elif isinstance(node, ast.Dict):
            keys = [_eval_node(k) for k in node.keys]
            values = [_eval_node(v) for v in node.values]
            return dict(zip(keys, values))

        elif isinstance(node, ast.List):
            return [_eval_node(item) for item in node.elts]

        elif isinstance(node, ast.Tuple):
            return tuple(_eval_node(item) for item in node.elts)

        elif isinstance(node, ast.Subscript):
            value = _eval_node(node.value)
            if isinstance(node.slice, ast.Index):
                # Python < 3.9
                index = _eval_node(node.slice.value)
            else:
                # Python >= 3.9
                index = _eval_node(node.slice)
            return value[index]

        elif isinstance(node, ast.BinOp):
            left = _eval_node(node.left)
            right = _eval_node(node.right)
            op_func = safe_operators.get(type(node.op))
            if op_func is None:
                raise ValueError(f"Unsupported binary operator: {type(node.op).__name__}")
            return op_func(left, right)

        elif isinstance(node, ast.UnaryOp):
            operand = _eval_node(node.operand)
            op_func = safe_operators.get(type(node.op))
            if op_func is None:
                raise ValueError(f"Unsupported unary operator: {type(node.op).__name__}")
            return op_func(operand)

        elif isinstance(node, ast.Compare):
            left = _eval_node(node.left)
            result = True
            for op, comparator in zip(node.ops, node.comparators):
                right = _eval_node(comparator)
                op_func = safe_operators.get(type(op))
                if op_func is None:
                    raise ValueError(f"Unsupported comparison operator: {type(op).__name__}")
                result = result and op_func(left, right)
                left = right
            return result

        elif isinstance(node, ast.BoolOp):
            op_func = safe_operators.get(type(node.op))
            if op_func is None:
                raise ValueError(f"Unsupported boolean operator: {type(node.op).__name__}")
            values = [_eval_node(v) for v in node.values]
            result = values[0]
            for value in values[1:]:
                result = op_func(result, value)
            return result

        elif isinstance(node, ast.IfExp):
            test = _eval_node(node.test)
            if test:
                return _eval_node(node.body)
            else:
                return _eval_node(node.orelse)

        else:
            raise ValueError(f"Unsupported expression type: {type(node).__name__}")

    result = _eval_node(tree)

    if not isinstance(result, dict):
        raise ValueError("Expression must evaluate to a dictionary")

    return result


def _validate_ast(tree):
    """
    Validate that the AST only contains safe node types.

    Args:
        tree: The AST to validate.

    Raises:
        ValueError: If the AST contains unsafe operations.
    """
    allowed_nodes = {
        ast.Expression, ast.Dict, ast.List, ast.Tuple, ast.Constant,
        ast.Name, ast.Load, ast.Subscript, ast.Index,
        ast.BinOp, ast.UnaryOp, ast.Compare, ast.BoolOp, ast.IfExp,
        # Operators
        ast.Add, ast.Sub, ast.Mult, ast.Div, ast.FloorDiv, ast.Mod, ast.Pow,
        ast.Eq, ast.NotEq, ast.Lt, ast.LtE, ast.Gt, ast.GtE,
        ast.And, ast.Or, ast.Not, ast.UAdd, ast.USub,
    }

    for node in ast.walk(tree):
        if type(node) not in allowed_nodes:
            raise ValueError(f"Unsafe operation detected: {type(node).__name__}")

"""
Workflow data transformation module for processing step outputs.
"""
import ast
import operator


class SafeTransformEvaluator(ast.NodeVisitor):
    """
    Safe evaluator for transformation expressions with restricted operations.
    """

    # Allowed operators
    SAFE_OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.And: operator.and_,
        ast.Or: operator.or_,
        ast.Not: operator.not_,
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def __init__(self, input_data: dict):
        self.input_data = input_data

    def eval(self, node):
        """Evaluate an AST node safely."""
        method_name = f'eval_{node.__class__.__name__}'
        method = getattr(self, method_name, None)
        if method is None:
            raise ValueError(f"Unsupported operation: {node.__class__.__name__}")
        return method(node)

    def eval_Expression(self, node):
        return self.eval(node.body)

    def eval_Dict(self, node):
        """Evaluate dictionary literal."""
        return {self.eval(k): self.eval(v) for k, v in zip(node.keys, node.values)}

    def eval_List(self, node):
        """Evaluate list literal."""
        return [self.eval(item) for item in node.elts]

    def eval_Tuple(self, node):
        """Evaluate tuple literal."""
        return tuple(self.eval(item) for item in node.elts)

    def eval_Constant(self, node):
        """Evaluate constant values (Python 3.8+)."""
        return node.value

    def eval_Num(self, node):
        """Evaluate numeric constants (Python 3.7 compatibility)."""
        return node.n

    def eval_Str(self, node):
        """Evaluate string constants (Python 3.7 compatibility)."""
        return node.s

    def eval_NameConstant(self, node):
        """Evaluate None, True, False (Python 3.7 compatibility)."""
        return node.value

    def eval_Name(self, node):
        """Evaluate variable names - only allow 'input_data'."""
        if node.id == 'input_data':
            return self.input_data
        raise ValueError(f"Access to variable '{node.id}' is not allowed. Only 'input_data' is permitted.")

    def eval_Subscript(self, node):
        """Evaluate subscript operations like input_data['key']."""
        value = self.eval(node.value)
        if isinstance(node.slice, ast.Index):
            # Python 3.7-3.8 compatibility
            index = self.eval(node.slice.value)
        else:
            # Python 3.9+
            index = self.eval(node.slice)
        return value[index]

    def eval_BinOp(self, node):
        """Evaluate binary operations."""
        op_type = type(node.op)
        if op_type not in self.SAFE_OPERATORS:
            raise ValueError(f"Binary operator {op_type.__name__} is not allowed")
        left = self.eval(node.left)
        right = self.eval(node.right)
        return self.SAFE_OPERATORS[op_type](left, right)

    def eval_UnaryOp(self, node):
        """Evaluate unary operations."""
        op_type = type(node.op)
        if op_type not in self.SAFE_OPERATORS:
            raise ValueError(f"Unary operator {op_type.__name__} is not allowed")
        operand = self.eval(node.operand)
        return self.SAFE_OPERATORS[op_type](operand)

    def eval_Compare(self, node):
        """Evaluate comparison operations."""
        left = self.eval(node.left)
        for op, comparator in zip(node.ops, node.comparators):
            op_type = type(op)
            if op_type not in self.SAFE_OPERATORS:
                raise ValueError(f"Comparison operator {op_type.__name__} is not allowed")
            right = self.eval(comparator)
            result = self.SAFE_OPERATORS[op_type](left, right)
            if not result:
                return False
            left = right
        return True

    def eval_BoolOp(self, node):
        """Evaluate boolean operations (and, or)."""
        op_type = type(node.op)
        if op_type not in self.SAFE_OPERATORS:
            raise ValueError(f"Boolean operator {op_type.__name__} is not allowed")

        values = [self.eval(value) for value in node.values]
        if isinstance(node.op, ast.And):
            return all(values)
        elif isinstance(node.op, ast.Or):
            return any(values)
        raise ValueError(f"Unsupported boolean operator: {op_type.__name__}")


def transform_step_data(transform_map_expr: str, input_data: dict) -> dict:
    """
    Transforms input data using a provided expression string.

    Args:
        transform_map_expr: A string representing a Python dictionary literal
                           that defines how to map input fields to output fields.
        input_data: Dictionary containing the input data from a previous step.

    Returns:
        A new dictionary with transformed data according to the expression.

    Raises:
        ValueError: If the expression contains unsupported or unsafe operations.
        SyntaxError: If the expression is not valid Python syntax.
    """
    try:
        # Parse the expression into an AST
        tree = ast.parse(transform_map_expr, mode='eval')

        # Create evaluator and safely evaluate the expression
        evaluator = SafeTransformEvaluator(input_data)
        result = evaluator.eval(tree)

        # Ensure the result is a dictionary
        if not isinstance(result, dict):
            raise ValueError("Transform expression must evaluate to a dictionary")

        return result
    except SyntaxError as e:
        raise SyntaxError(f"Invalid expression syntax: {e}")
    except Exception as e:
        raise ValueError(f"Error evaluating transform expression: {e}")
